Here's a basic implementation of the Snake game in C using SDL library for graphics and animation.

**Note:** This code uses SDL2 library, which is a cross-platform development library designed to provide low level access to audio, keyboard, mouse, joystick, and graphics hardware via OpenGL and Direct3D.

**snake_game.c**
```c
#include <SDL2/SDL.h>
#include <SDL2/SDL_image.h>
#include <stdio.h>
#include <stdlib.h>
#include <time.h>

#define SCREEN_WIDTH 640
#define SCREEN_HEIGHT 480

#define SNAKE_SPEED 10

// Define the snake's initial direction
enum Direction { UP, DOWN, LEFT, RIGHT };
enum Direction snake_direction = RIGHT;

// Define the snake's initial position and size
int snake_x = SCREEN_WIDTH / 2;
int snake_y = SCREEN_HEIGHT / 2;
int snake_length = 5;

// Define the snake's body parts
int snake_body[snake_length][2];

// Define the food's position
int food_x;
int food_y;

// Define the score
int score = 0;

// Define the game over flag
int game_over = 0;

// Load images
SDL_Texture* snake_head;
SDL_Texture* snake_body_part;
SDL_Texture* food;

// Initialize SDL
SDL_Init(SDL_INIT_VIDEO);

// Create the game window
SDL_Window* window = SDL_CreateWindow("Snake Game", SDL_WINDOWPOS_CENTERED, SDL_WINDOWPOS_CENTERED, SCREEN_WIDTH, SCREEN_HEIGHT, SDL_WINDOW_SHOWN);

// Create the renderer
SDL_Renderer* renderer = SDL_CreateRenderer(window, -1, SDL_RENDERER_ACCELERATED);

// Load images
snake_head = IMG_LoadTexture(renderer, "snake_head.png");
snake_body_part = IMG_LoadTexture(renderer, "snake_body_part.png");
food = IMG_LoadTexture(renderer, "food.png");

// Main game loop
while (!game_over) {
    // Handle events
    SDL_Event event;
    while (SDL_PollEvent(&event)) {
        if (event.type == SDL_QUIT) {
            game_over = 1;
        }
        if (event.type == SDL_KEYDOWN) {
            switch (event.key.keysym.sym) {
                case SDLK_UP:
                    snake_direction = UP;
                    break;
                case SDLK_DOWN:
                    snake_direction = DOWN;
                    break;
                case SDLK_LEFT:
                    snake_direction = LEFT;
                    break;
                case SDLK_RIGHT:
                    snake_direction = RIGHT;
                    break;
            }
        }
    }

    // Update snake's position
    switch (snake_direction) {
        case UP:
            snake_y -= SNAKE_SPEED;
            break;
        case DOWN:
            snake_y += SNAKE_SPEED;
            break;
        case LEFT:
            snake_x -= SNAKE_SPEED;
            break;
        case RIGHT:
            snake_x += SNAKE_SPEED;
            break;
    }

    // Check collisions with walls and self
    if (snake_x < 0 || snake_x >= SCREEN_WIDTH || snake_y < 0 || snake_y >= SCREEN_HEIGHT) {
        game_over = 1;
    }
    for (int i = 0; i < snake_length; i++) {
        if (snake_body[i][0] == snake_x && snake_body[i][1] == snake_y) {
            game_over = 1;
        }
    }

    // Check if snake eats food
    if (snake_x == food_x && snake_y == food_y) {
        score++;
        snake_length++;
        food_x = rand() % SCREEN_WIDTH;
        food_y = rand() % SCREEN_HEIGHT;
    }

    // Update snake's body
    for (int i = snake_length - 1; i > 0; i--) {
        snake_body[i][0] = snake_body[i - 1][0];
        snake_body[i][1] = snake_body[i - 1][1];
    }
    snake_body[0][0] = snake_x;
    snake_body[0][1] = snake_y;

    // Render game
    SDL_RenderClear(renderer);

    // Render snake's head
    SDL_Rect snake_head_rect = { snake_x, snake_y, 10, 10 };
    SDL_RenderCopy(renderer, snake_head, NULL, &snake_head_rect);

    // Render snake's body
    for (int i = 1; i < snake_length; i++) {
        snake_body_rect = { snake_body[i][0], snake_body[i][1], 10, 10 };
        SDL_RenderCopy(renderer, snake_body_part, NULL, &snake_body_rect);
    }

    // Render food
    SDL_Rect food_rect = { food_x, food_y, 10, 10 };
    SDL_RenderCopy(renderer, food, NULL, &food_rect);

    // Update screen
    SDL_RenderPresent(renderer);

    // Delay
    SDL_Delay(1000 / 60);
}

// Clean up
SDL_DestroyRenderer(renderer);
SDL_DestroyWindow(window);
IMG_FreeTexture(snake_head);
IMG_FreeTexture(snake_body_part);
IMG_FreeTexture(food);
SDL_Quit();
```
**How to compile and run:**

1. Install SDL2 library: `sudo apt-get install libsdl2-dev` (on Ubuntu-based systems)
2. Compile the code: `gcc snake_game.c -o snake_game -lSDL2 -lSDL2_image`
3. Run the game: `./snake_game`

**Note:** This code uses `snake_head.png`, `snake_body_part.png`, and `food.png` images. You need to create these images and place them in the same directory as the executable.

**Tips:**

* To make the game smoother, you can increase the `SNAKE_SPEED` variable.
* To add more features, you can add more game logic, such as scoring, levels, and sound effects.
* You can also improve the game's graphics by using more advanced rendering techniques, such as texture mapping or particle systems.

